const body = $input.first().json.body || $input.first().json;
const query = (body.query || '').toLowerCase();

// Base de données tarifs TalosPrimes
const tarifs = {
  entreprise: {
    nom: 'TalosPrimes',
    site: 'https://talosprimes.com',
    email: 'direction@talosprimes.com',
    description: 'Plateforme SaaS B2B de gestion d\'entreprise intelligente avec automatisations IA'
  },
  delais: {
    livraison_standard: '48h a 72h apres validation du paiement',
    livraison_complexe: '5 a 10 jours ouvres (projets sur mesure)',
    support_inclus: 'Support email inclus dans l\'abonnement',
    essai_gratuit: 'Demonstration gratuite sur demande'
  },
  infos_necessaires: [
    'Nom de l\'entreprise',
    'Secteur d\'activite',
    'Adresse email professionnelle',
    'Nombre d\'utilisateurs prevu',
    'Modules souhaites',
    'Besoins specifiques'
  ],
  catalogue: [
    { nom: 'Gestion Email Automatisee', categorie: 'email', setup: 799, abonnement: 59, desc: 'Tri IA, reponses auto, templates, newsletters, relances, sequences bienvenue' },
    { nom: 'Agent IA Telephone', categorie: 'telephone', setup: 999, abonnement: 79, desc: 'Agent vocal IA, qualification leads, RDV auto, SMS, questionnaires' },
    { nom: 'CRM & Gestion Clients', categorie: 'crm', setup: 599, abonnement: 49, desc: 'Clients, devis, factures, bons de commande, avoirs, proformas' },
    { nom: 'Comptabilite', categorie: 'comptabilite', setup: 899, abonnement: 69, desc: 'Plan comptable, journaux, ecritures, exercices, grand livre' },
    { nom: 'Marketing Digital', categorie: 'marketing', setup: 699, abonnement: 59, desc: 'Reseaux sociaux auto, calendrier editorial, campagnes, analytics' }
  ],
  formules: [
    { nom: 'Essentiel', modules: 1, prix: 49, users: 3, cible: 'TPE' },
    { nom: 'Business', modules: 3, prix: 129, users: 10, cible: 'PME' },
    { nom: 'Enterprise', modules: 'illimite', prix: 299, users: 'illimite', cible: 'Grandes entreprises' }
  ],
  conditions: {
    paiement: 'Virement bancaire ou carte (Stripe)',
    engagement: 'Sans engagement — resiliation a tout moment',
    tva: 'Prix HT — TVA 20% applicable',
    remise_annuelle: '2 mois offerts pour engagement annuel'
  }
};

// Filtrer si une query specifique est demandee
let result = tarifs;
if (query.includes('email')) {
  result = { module: tarifs.catalogue.find(c => c.categorie === 'email'), delais: tarifs.delais, infos_necessaires: tarifs.infos_necessaires, conditions: tarifs.conditions };
} else if (query.includes('telephone') || query.includes('appel') || query.includes('vocal')) {
  result = { module: tarifs.catalogue.find(c => c.categorie === 'telephone'), delais: tarifs.delais, infos_necessaires: tarifs.infos_necessaires, conditions: tarifs.conditions };
} else if (query.includes('crm') || query.includes('client') || query.includes('factur')) {
  result = { module: tarifs.catalogue.find(c => c.categorie === 'crm'), delais: tarifs.delais, infos_necessaires: tarifs.infos_necessaires, conditions: tarifs.conditions };
} else if (query.includes('compta')) {
  result = { module: tarifs.catalogue.find(c => c.categorie === 'comptabilite'), delais: tarifs.delais, infos_necessaires: tarifs.infos_necessaires, conditions: tarifs.conditions };
} else if (query.includes('marketing')) {
  result = { module: tarifs.catalogue.find(c => c.categorie === 'marketing'), delais: tarifs.delais, infos_necessaires: tarifs.infos_necessaires, conditions: tarifs.conditions };
}

return [{ json: { success: true, data: result } }];
